pub fn updatewindow(strm: &mut InflateStream, end: &[u8], copy: usize) -> Result<(), InflateError> {
    let s = &mut strm.state;
    // Allocate the window on first use.
    if s.window.is_empty() {
        let size = 1usize << (s.wbits as usize);
        s.window = vec![0u8; size];
        s.wsize = size as u32;
        s.wnext = 0;
        s.whave = 0;
    }
    let wsize = s.wsize as usize;
    // Copy the last `copy` bytes from `end` into the window, wrapping.
    if copy >= wsize {
        // End bytes overflow a whole window — keep only the final wsize.
        let src = &end[end.len().saturating_sub(wsize)..];
        s.window[..wsize].copy_from_slice(src);
        s.wnext = 0;
        s.whave = wsize as u32;
    } else {
        let src = &end[end.len().saturating_sub(copy)..];
        let wnext = s.wnext as usize;
        let dist = wsize - wnext;
        let first = copy.min(dist);
        s.window[wnext..wnext + first].copy_from_slice(&src[..first]);
        if copy > first {
            s.window[..copy - first].copy_from_slice(&src[first..]);
            s.wnext = (copy - first) as u32;
        } else {
            let new_wnext = wnext + first;
            s.wnext = (if new_wnext == wsize { 0 } else { new_wnext }) as u32;
        }
        let new_have = (s.whave as usize + copy).min(wsize);
        s.whave = new_have as u32;
    }
    Ok(())
}

pub fn buildtables() -> (alloc::vec::Vec<(u8, u8, u16)>, alloc::vec::Vec<(u8, u8, u16)>) {
    let mut lens = alloc::vec::Vec::with_capacity(288);
    for sym in 0u16..288 {
        let len: u8 = match sym {
            0..=143 => 8,
            144..=255 => 9,
            256..=279 => 7,
            _ => 8,
        };
        lens.push((0u8, len, sym));
    }
    let mut dists = alloc::vec::Vec::with_capacity(32);
    for sym in 0u16..32 {
        dists.push((0u8, 5u8, sym));
    }
    (lens, dists)
}

pub fn inflate_fixed(strm: &mut InflateStream) -> Result<(), InflateError> {
    let (lens, dists) = buildtables();
    strm.state.lencode = lens;
    strm.state.distcode = dists;
    strm.state.lenbits = 9;
    strm.state.distbits = 5;
    Ok(())
}
